    @abstractmethod
    def evaluate(self, schema: Dict[str, str]) -> str:
        pass

class Select(RelationalOperator):
    def __init__(self, attributes: List[str]):
        self.attributes = attributes

    def evaluate(self, schema: Dict[str, str]) -> str:
        return f"SELECT {', '.join(self.attributes)}"

class Project(RelationalOperator):
    def __init__(self, attributes: List[str]):
        self.attributes = attributes

    def evaluate(self, schema: Dict[str, str]) -> str:
        return f"PROJECT {', '.join(self.attributes)}"

